def numberToWords(num):
    if num == 0: return 'Zero'
    def helper(n):
        if n < 20: return ones[n]
        if n < 100: return tens[n//10] + ('' if n%10==0 else ' ' + ones[n%10])
        return ones[n//100] + ' Hundred' + ('' if n%100==0 else ' ' + helper(n%100))
    ones = ['', 'One', 'Two', 'Three', 'Four', 'Five', 'Six', 'Seven', 'Eight', 'Nine', 'Ten', 'Eleven', 'Twelve', 'Thirteen', 'Fourteen', 'Fifteen', 'Sixteen', 'Seventeen', 'Eighteen', 'Nineteen']
    tens = ['', '', 'Twenty', 'Thirty', 'Forty', 'Fifty', 'Sixty', 'Seventy', 'Eighty', 'Ninety']
    res = ''; bills = num // 10**9; num %= 10**9
    if bills: res += helper(bills) + ' Billion '
    mils = num // 10**6; num %= 10**6
    if mils: res += helper(mils) + ' Million '
    thous = num // 10**3; num %= 10**3
    if thous: res += helper(thous) + ' Thousand '
    if num: res += helper(num)
    return res.strip()

